#include <iostream>
using namespace std;

class Base {
public:
 virtual void display() {
 cout << "Base::display() called" << endl;
 }
 virtual ~Base() {}
};

class Derived : public Base {
public:
 void display() override {
 cout << "Derived::display() called" << endl;
 }
};

int main() {
 Base* ptr = new Derived(); // Pointer to Base, object is Derived
 ptr->display(); // Calls Derived::display() - hierarchical!

 Base objBase;
 Base& ref = objBase;
 ref.display(); // Calls Base::display()

 delete ptr;
 return 0;
}

#include <iostream>
using namespace std;

class Shape {
public:
 virtual double area() = 0; // Pure virtual function
 virtual void draw() = 0; // Another pure virtual
 virtual ~Shape() {}
};

class Circle : public Shape {
 double radius;
public:
 Circle(double r) : radius(r) {}
 double area() override {
 return 3.14159 * radius * radius;
 }
 void draw() override {
 cout << "Drawing Circle" << endl;
 }
};

class Rectangle : public Shape {
 double length, breadth;
public:
 Rectangle(double l, double b) : length(l), breadth(b) {}
 double area() override {
 return length * breadth;
 }
 void draw() override {
 cout << "Drawing Rectangle" << endl;
 }
};

int main() {
 Shape* shapes[2];
 shapes[0] = new Circle(5);
 shapes[1] = new Rectangle(4, 6);

 for(int i=0; i<2; i++) {
 shapes[i]->draw();
 cout << "Area: " << shapes[i]->area() << endl;
 }
 return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
 // Without virtual: only Base destructor called
 // With virtual: Derived then Base destructors called
 virtual ~Base() {
 cout << "Base destructor" << endl;
 }
};

class Derived : public Base {
 int* data;
public:
 Derived() { data = new int[100]; }
 ~Derived() {
 cout << "Derived destructor - freeing memory" << endl;
 delete[] data;
 }
};

int main() {
 Base* ptr = new Derived();
 delete ptr; // Without virtual: MEMORY LEAK!
 // With virtual: Calls Derived then Base
 return 0;
}

#include <iostream>
using namespace std;

class Device {
public:
 string name;
 Device(string n) : name(n) {}
 virtual void spec() {
 cout << "Device: " << name << endl;
 }
};

// Virtual inheritance - shares single Device instance
class Keyboard : virtual public Device {
public:
 Keyboard() : Device("Generic Keyboard") {}
 void spec() override {
 cout << "Keyboard spec: Mechanical keys" << endl;
 }
};

class Monitor : virtual public Device {
public:
 Monitor() : Device("Generic Monitor") {}
 void spec() override {
 cout << "Monitor spec: LED display" << endl;
 }
};

class Computer : public Keyboard, public Monitor {
public:
 Computer() : Device("Custom Computer") {}
 void spec() override {
 cout << "Computer: Combined spec" << endl;
 }
};

int main() {
 Computer comp;
 Device* ptr = &comp;
 ptr->spec(); // Calls Computer::spec()
 return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
 virtual void process() {
 cout << "Base::process" << endl;
 }
 virtual void finalMethod() final {
 cout << "Cannot override this" << endl;
 }
};

class Derived : public Base {
public:
 void process() override { // Explicit override
 cout << "Derived::process" << endl;
 }
 // Error if uncommented - final prevents override
 // void finalMethod() override {}
};

class FinalClass : public Derived {
public:
 void process() override {
 cout << "FinalClass::process" << endl;
 }
 // Cannot override finalMethod from Base
};

int main() {
 Base* ptr = new FinalClass();
 ptr->process(); // Calls FinalClass::process - hierarchical!
 ptr->finalMethod(); // Calls Base::finalMethod - it's final
 return 0;
}
